import logging
import json
from datetime import datetime
from typing import Dict, Any
import re

class WebAppLogger:
    def __init__(self, log_file: str = "app.log"):
        self.log_file = log_file
        self.logger = logging.getLogger("WebAppLogger")
        self.logger.setLevel(logging.INFO)
        
        # Prevent duplicate handlers
        if not self.logger.handlers:
            handler = logging.FileHandler(log_file)
            formatter = logging.Formatter(
                '%(asctime)s - %(name)s - %(levelname)s - %(message)s'
            )
            handler.setFormatter(formatter)
            self.logger.addHandler(handler)
    
    def log_request(self, request_data: Dict[str, Any], response_data: Dict[str, Any] = None):
        """Log HTTP request and response data securely"""
        try:
            # Sanitize input data to prevent log injection
            sanitized_request = self._sanitize_log_data(request_data)
            sanitized_response = self._sanitize_log_data(response_data) if response_data else {}
            
            # Create structured log entry
            log_entry = {
                "timestamp": datetime.utcnow().isoformat(),
                "request": sanitized_request,
                "response": sanitized_response
            }
            
            # Write to log file using safe string formatting
            log_message = json.dumps(log_entry, separators=(',', ':'))
            self.logger.info(log_message)
            
        except Exception as e:
            # Fallback logging in case of sanitization errors
            fallback_message = f"LOGGING_ERROR: {str(e)}"
            self.logger.error(fallback_message)
    
    def _sanitize_log_data(self, data: Dict[str, Any]) -> Dict[str, Any]:
        """Sanitize log data to prevent log injection"""
        if not isinstance(data, dict):
            return {"error": "Invalid data format"}
        
        sanitized = {}
        for key, value in data.items():
            # Sanitize key names
            safe_key = re.sub(r'[\r\n\t]', '', str(key))
            # Sanitize values
            if isinstance(value, str):
                safe_value = re.sub(r'[\r\n\t]', ' ', value)
                sanitized[safe_key] = safe_value
            else:
                sanitized[safe_key] = value
        return sanitized

